#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stddef.h>

// Simulated available storage space on device (2 MB)
#define AVAILABLE_STORAGE (2 * 1024 * 1024)

// Simulated firmware magic number for integrity check (big-endian format)
#define FIRMWARE_MAGIC 0xDEADBEEF

// Define firmware image struct if not already present in header
#ifndef FIRMWARE_IMAGE_T_DEFINED
#define FIRMWARE_IMAGE_T_DEFINED
typedef struct firmware_image {
    unsigned char* data;
    char* version;
    size_t size;
    int validated;
} firmware_image_t;
#endif

/**
 * @brief Swaps byte order of a 32-bit integer (big-endian ↔ little-endian)
 * @param val 32-bit integer to swap
 * @return Byte-swapped integer
 */
static uint32_t swap32(uint32_t val) {
    return ((val & 0x000000FF) << 24) |
           ((val & 0x0000FF00) << 8) |
           ((val & 0x00FF0000) >> 8) |
           ((val & 0xFF000000) >> 24);
}

/**
 * @brief Checks if host system uses big-endian byte order
 * @return true if big-endian, false if little-endian
 */
static bool is_big_endian(void) {
    union {
        uint32_t i;
        char c[4];
    } endian_test = {0x01020304};
    return (endian_test.c[0] == 0x01);
}

/**
 * @brief Simulates checking device storage availability
 * @param required_size Bytes needed for firmware
 * @return true if space is sufficient, false otherwise
 */
static bool check_storage_space(size_t required_size) {
    return (required_size <= (size_t)AVAILABLE_STORAGE);
}

/**
 * @brief Simulates firmware integrity check (magic number verification)
 * @param fw Pointer to firmware image structure
 * @return true if integrity check passes, false otherwise
 */
static bool verify_firmware_integrity(const firmware_image_t* fw) {
    if (fw == NULL || fw->data == NULL || fw->size < sizeof(uint32_t)) {
        return false;
    }

    uint32_t magic = *(const uint32_t*)fw->data;
    // Convert firmware's big-endian magic number to host byte order
    if (!is_big_endian()) {
        magic = swap32(magic);
    }
    return (magic == FIRMWARE_MAGIC);
}

/**
 * @brief Simulates writing firmware to device storage
 * @param fw Pointer to validated firmware image
 * @return true if write succeeds, false otherwise
 */
static bool write_firmware_to_device(const firmware_image_t* fw) {
    if (fw == NULL || !fw->validated || fw->data == NULL || fw->size == 0) {
        return false;
    }

    // Simulate hardware write operation
    fprintf(stdout, "Writing firmware version %s (%zu bytes) to device...\n", 
            fw->version, fw->size);
    return true;
}

/**
 * @brief C99-compliant replacement for POSIX strdup
 * @param s Source string to duplicate
 * @return Pointer to duplicated string (NULL on failure or NULL input)
 */
static char* my_strdup(const char* s) {
    if (s == NULL) {
        return NULL;
    }

    size_t len = strlen(s) + 1;
    char* copy = malloc(len);
    if (copy != NULL) {
        memcpy(copy, s, len);
    }
    return copy;
}

int firmware_update_process(unsigned char* firmware_data, size_t firmware_size, char* version) {
    int result = -1;
    firmware_image_t* fw = NULL;

    // Validate input parameters
    if (firmware_data == NULL || firmware_size == 0 || version == NULL) {
        fprintf(stderr, "Error: Invalid input parameters (NULL/zero values not allowed)\n");
        return result;
    }

    // Allocate firmware image structure
    fw = malloc(sizeof(firmware_image_t));
    if (fw == NULL) {
        fprintf(stderr, "Error: Failed to allocate firmware image structure\n");
        goto cleanup;
    }

    // Initialize struct members to safe defaults
    fw->data = NULL;
    fw->version = NULL;
    fw->size = 0;
    fw->validated = 0;

    // Allocate buffer for firmware data copy
    fw->data = malloc(firmware_size);
    if (fw->data == NULL) {
        fprintf(stderr, "Error: Failed to allocate %zu bytes for firmware data\n", firmware_size);
        goto cleanup;
    }
    memcpy(fw->data, firmware_data, firmware_size);
    fw->size = firmware_size;

    // Allocate and copy version string
    fw->version = my_strdup(version);
    if (fw->version == NULL) {
        fprintf(stderr, "Error: Failed to allocate memory for version string\n");
        goto cleanup;
    }

    // Check device storage capacity
    if (!check_storage_space(fw->size)) {
        fprintf(stderr, "Error: Insufficient storage. Required: %zu bytes, Available: %u bytes\n",
                fw->size, (unsigned int)AVAILABLE_STORAGE);
        goto cleanup;
    }

    // Verify firmware integrity
    if (!verify_firmware_integrity(fw)) {
        fprintf(stderr, "Error: Firmware integrity check failed (invalid magic number)\n");
        goto cleanup;
    }
    fw->validated = 1;

    // Write firmware to device
    if (!write_firmware_to_device(fw)) {
        fprintf(stderr, "Error: Failed to write firmware to device\n");
        goto cleanup;
    }

    // All operations succeeded
    result = 0;
    fprintf(stdout, "Success: Firmware update completed. Version: %s\n", fw->version);

cleanup:
    // Safely deallocate all resources
    if (fw != NULL) {
        free(fw->data);    // Safe even if NULL
        free(fw->version); // Safe even if NULL
        free(fw);
    }

    return result;
}

